package controllers

import play.api.mvc._
import play.api.libs.json.Json
import slick.jdbc.PostgresProfile.api._

import scala.concurrent.ExecutionContext.Implicits.global

class ProductController(db: Database) extends Controller {

  case class Product(id: Int, name: String, price: Double)

  def searchProducts = Action.async {
    val searchParams = request.queryString
    val filters = buildFilters(searchParams)
    val sqlFragment = filters.mkString(" AND ")
    val query = sql"SELECT * FROM products WHERE $sqlFragment".as[Product]
    
    db.run(query).map(products => Ok(Json.toJson(products)))
  }

  private def buildFilters(params: Map[String, Seq[String]]): Seq[String] = {
    params.flatMap { case (key, values) =>
      values.map(value => s"$key ILIKE '%$value%'")
    }
  }
}